class Solution {
    public long countGoodIntegers(int n, int k) {
        long res = 0;
        int[] cnt = new int[10];
        cnt[0] = 1;
        for (int i = 1; i <= 9; i++) {
            cnt[i] = (i % k == 0) ? 1 : 0;
        }
        for (int i = 1; i < n; i++) {
            int[] next = new int[10];
            for (int j = 0; j < 10; j++) {
                for (int l = 0; l < 10; l++) {
                    next[(j + l) % 10] += cnt[j];
                }
            }
            cnt = next;
        }
        for (int i = 1; i < 10; i++) {
            res += cnt[(k - i) % 10];
        }
        return res;
    }
}
